#include <iostream>
#include <tuple>
#include <string>

using namespace std;

int main()
{
    tuple<string, int, double> student = {"Aman", 20, 88.5};

    cout << get<0>(student) << endl;
    cout << get<1>(student) << endl;
    cout << get<2>(student) << endl;

    return 0;
}

string name;
int age;
double marks;

tie(name, age, marks) = student; // unpacks all three values at once

cout << name << " " << age << " " << marks;

